async (params, browser) => {
  // Search vacation packages
  await browser.open(`https://www.expedia.com/go/package/search/FlightHotel/${params.departure_date}/${params.return_date}?FromAirport=${params.origin}&Destination=${params.destination}&NumRoom=1&NumAdult=2`)

  // Wait for package results
  await browser.waitForSelector('[data-stid=\'lodging-card-responsive\'], [data-stid=\'property-listing\'], [data-stid=\'section-results\'] li', 25000)

  // Let results render
  await browser.wait(3000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract package results
  const package_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[data-stid="lodging-card-responsive"], [data-stid="property-listing"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const hotelEl = el.querySelector('h3, h2'); const priceEl = el.querySelector('[data-test-id="price-summary-message-line"] span, [data-stid="price-lockup"] span'); const savingsEl = el.querySelector('[data-stid*="savings"], [aria-label*="savings"], [data-stid*="discount"]'); const ratingEl = el.querySelector('span.is-visually-hidden, [aria-label*="rating"]'); const imgEl = el.querySelector('img'); const linkEl = el.querySelector('a[data-stid="open-hotel-information"], a[href*="Hotel-Information"], a[href*=".h"]'); const flightEl = el.querySelector('[data-stid*="flight"], [aria-label*="flight"]'); const url = linkEl ? (linkEl.href.startsWith('http') ? linkEl.href : 'https://www.expedia.com' + linkEl.getAttribute('href')) : ''; results.push({ hotel_name: hotelEl ? hotelEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', savings: savingsEl ? savingsEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', flight_info: flightEl ? flightEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', url: url }); } return { origin: params.origin, destination: params.destination, departure_date: params.departure_date, return_date: params.return_date, result_count: results.length, results: results }`)

  return package_results
}
